import{_ as c,C as t,o,c as d,a2 as r,b as i,w as a,a as n,E as l,a3 as u,j as p}from"./chunks/framework.DvFsUg-r.js";const C=JSON.parse('{"title":"설계 저널 게시 파이프라인 구축기","description":"","frontmatter":{"slug":"docs-pipeline","title":"설계 저널 게시 파이프라인 구축기","authors":[],"tags":["docs","docusaurus","spec-kit","github-actions","ci"],"created":"2026-05-30 13:14 (KST)","date":"2026-05-30T04:14:00.000Z"},"headers":[],"relativePath":"journal/2026-05-30-docs-pipeline.md","filePath":"journal/2026-05-30-docs-pipeline.md","lastUpdated":1781092690000}'),g={name:"journal/2026-05-30-docs-pipeline.md"};function h(b,e,_,B,m,f){const s=t("Mermaid");return o(),d("div",null,[e[1]||(e[1]=r('<p>이 사이트 자체를 만든 이야기다. spec 을 쓰고 글을 쓰면 <code>main</code> 푸시만으로 자동 배포되는 <strong>설계 저널 게시 파이프라인</strong>을 구축했다. 그 과정에서 만난 오류와 결정들을 시간순으로 정리한다.</p><h2 id="목표" tabindex="-1">목표 <a class="header-anchor" href="#목표" aria-label="Permalink to &quot;목표&quot;">​</a></h2><ul><li>설계자는 마크다운(spec / journal)만 쓰면 된다.</li><li><code>main</code> 에 푸시하면 사람이 손대지 않아도 사이트가 갱신된다.</li><li>설계 문서의 단일 출처는 <code>specs/</code>, 게시는 자동.</li></ul><p>전체 흐름과 정식 명세는 <a href="/specs/002-docs-publishing-pipeline/spec">게시 파이프라인 spec</a> 에 정리해 두었다. 아래는 만들면서 겪은 트러블슈팅 로그다.</p><h2 id="_1-docusaurus-기동-—-연쇄-오류-풀기" tabindex="-1">1. Docusaurus 기동 — 연쇄 오류 풀기 <a class="header-anchor" href="#_1-docusaurus-기동-—-연쇄-오류-풀기" aria-label="Permalink to &quot;1. Docusaurus 기동 — 연쇄 오류 풀기&quot;">​</a></h2><p><code>docusaurus start</code> 가 처음부터 깨졌다. 원인은 하나의 설정에서 줄줄이 파생됐다.</p><ul><li><strong><code>future: { v4: true }</code></strong> 가 <code>fasterByDefault</code> 를 켜면서 Rspack 기반 빌더를 요구 → <code>@docusaurus/faster</code> 패키지를 설치해 해결.</li><li>같은 v4 플래그가 <code>.md</code> 의 MDX1 호환을 끄면서, 저널 글의 HTML 주석</li></ul><p>:::tip[교훈] <code>future.v4: true</code> 는 단일 토글이 아니라 <strong>여러 미래 플래그를 한꺼번에 켜는 메가 플래그</strong>다. 켜는 순간 빌더·MDX 호환성까지 바뀐다. :::</p><h2 id="_2-페이지를-찾을-수-없습니다" tabindex="-1">2. &quot;페이지를 찾을 수 없습니다&quot; <a class="header-anchor" href="#_2-페이지를-찾을-수-없습니다" aria-label="Permalink to &quot;2. &quot;페이지를 찾을 수 없습니다&quot;&quot;">​</a></h2><p>docs 를 <code>/specs</code>, blog 를 <code>/journal</code> 로 옮겨놓으니 정작 루트 <code>/</code> 에 매핑되는 페이지가 사라져 홈이 404 였다.</p><ul><li><code>src/pages/index.js</code> <strong>홈 랜딩 페이지</strong>를 추가.</li><li>그리고 더 미묘한 문제: <code>routeBasePath: &#39;specs&#39;</code> 인데 문서도 <code>docs/specs/</code> 폴더 안에 있어 URL 이 <code>/specs/specs/intro</code> 로 <strong>중복</strong>됐다. → 문서를 <code>docs/</code> 바로 아래로 옮기고, 뒤이어 동기화 스크립트의 대상 경로도 <code>blog/docs</code> 로 맞춰 중복을 원천 차단.</li></ul><h2 id="_3-테마-—-hasura-문서-테마-이식" tabindex="-1">3. 테마 — Hasura 문서 테마 이식 <a class="header-anchor" href="#_3-테마-—-hasura-문서-테마-이식" aria-label="Permalink to &quot;3. 테마 — Hasura 문서 테마 이식&quot;">​</a></h2><p>처음엔 보라/시안 톤으로 만들었다가, Hasura 문서 사이트와 동일하게 가기로 했다. &quot;설치형 테마 패키지&quot; 같은 건 없고, 그 사이트도 우리와 같은 Docusaurus 라 <strong>디자인 토큰을 복제</strong>하는 게 정석이었다.</p><p><code>hasura/graphql-engine</code> 의 <code>default-fonts-and-colors.scss</code> 에서 실제 값을 떠와 이식했다.</p><ul><li>Primary 블루 <code>#0b89d0</code>, 커스텀 그레이 스케일, 다크 배경 <code>#141c22</code></li><li>본문 <strong>IBM Plex Sans</strong>, 코드 <strong>IBM Plex Mono</strong> (Google Fonts)</li><li>라이트 기본 + 시스템 설정 따름</li></ul><h2 id="_4-github-actions-자동-배포" tabindex="-1">4. GitHub Actions 자동 배포 <a class="header-anchor" href="#_4-github-actions-자동-배포" aria-label="Permalink to &quot;4. GitHub Actions 자동 배포&quot;">​</a></h2><p><code>main</code> 푸시 시 <code>checkout → spec 동기화 → build → GitHub Pages 배포</code> 가 도는 워크플로를 붙였다. 여기서도 두 가지에 막혔다.</p><ul><li><strong><code>Get Pages site failed</code></strong> — 워크플로 기본 토큰은 Pages 사이트를 새로 <strong>생성할 권한이 없다</strong>. 저장소에서 Pages 를 &#39;GitHub Actions&#39; 소스로 1회 활성화하고, <code>configure-pages</code> 에 <code>enablement: true</code> 를 더해 해결.</li><li><strong>Node 20 deprecation 경고</strong> — <code>checkout@v5</code>, <code>setup-node@v5</code> 로 올리고, 아직 Node 24 상위 버전이 없는 Pages 액션들은 <code>FORCE_JAVASCRIPT_ACTIONS_TO_NODE24=true</code> 로 강제 실행.</li></ul><p>추가로 Windows/리눅스 줄바꿈 차이를 막으려 <code>.gitattributes</code> 로 <strong>LF 정규화</strong> 정책을 고정했다.</p><p>:::info[품질 게이트] <code>deploy</code> job 은 <code>build</code> 에 <code>needs</code> 로 묶여 있다. <strong>빌드가 깨지면 배포는 중단</strong>되고 이전 버전이 유지된다. 잘못된 콘텐츠가 게시되지 않는 안전장치다. :::</p><h2 id="_5-spec-kit-로-사후-문서화" tabindex="-1">5. spec-kit 로 사후 문서화 <a class="header-anchor" href="#_5-spec-kit-로-사후-문서화" aria-label="Permalink to &quot;5. spec-kit 로 사후 문서화&quot;">​</a></h2><p>마지막으로, 지금까지 만든 인프라 자체를 <strong>spec-kit 로 정리</strong>했다. <code>/speckit-specify</code> 로 게시 파이프라인 명세(FR-1~16, 성공 기준 SC-1~6)를 쓰고, 전체 흐름을 Mermaid 다이어그램으로 그려 한눈에 보이게 했다.</p><p>그 과정에서 또 하나 발견: 동기화 스크립트가 <code>checklists/</code> 같은 내부 QA 산출물까지 사이트로 노출시켜서, <code>checklists/</code> 를 동기화 대상에서 제외했다.</p><h2 id="결과" tabindex="-1">결과 <a class="header-anchor" href="#결과" aria-label="Permalink to &quot;결과&quot;">​</a></h2>',24)),(o(),i(u,null,{default:a(()=>[l(s,{id:"mermaid-127",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22%EB%A7%88%ED%81%AC%EB%8B%A4%EC%9A%B4%20%EC%9E%91%EC%84%B1%3Cbr%2F%3Espec%20%2F%20journal%22%5D%20--%3E%20B%5B%22git%20push%20%E2%86%92%20main%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22GitHub%20Actions%3Cbr%2F%3E%EB%8F%99%EA%B8%B0%ED%99%94%20%C2%B7%20%EB%B9%8C%EB%93%9C%20%C2%B7%20%EB%B0%B0%ED%8F%AC%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22coffeeman1.github.io%2Fblog%3Cbr%2F%3E%EC%9E%90%EB%8F%99%20%EA%B0%B1%EC%8B%A0%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=p("p",null,"이제 이 글처럼, 저널 마크다운 하나를 커밋하고 푸시하면 몇 분 뒤 사이트에 올라온다. 파이프라인이 스스로를 게시하는 셈이다.",-1))])}const A=c(g,[["render",h]]);export{C as __pageData,A as default};
